package org.apache.commons.jxpath.ri.model.dom;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.jxpath.ri.model.dom.steps"
)
public class CucumberTest {
}

package org.apache.commons.jxpath.ri.model.dom.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import org.apache.commons.jxpath.JXPathContext;
import org.apache.commons.jxpath.Pointer;
import org.apache.commons.jxpath.xml.DocumentContainer;
import org.junit.Assert;
import org.w3c.dom.Element;
import org.apache.commons.jxpath.JXPathTestCase;

import java.net.URL;

public class StepDefs {

    private JXPathContext context;
    private Object result;

    @Given("a DOM model with a root element named {string}")
    public void a_dom_model_with_a_root_element_named(String rootName) {
        URL url = JXPathTestCase.class.getResource("Vendor.xml");
        Assert.assertNotNull("Vendor.xml not found", url);
        DocumentContainer docCtr = new DocumentContainer(url, DocumentContainer.MODEL_DOM);
        context = JXPathContext.newContext(docCtr);
    }

    @When("I evaluate the XPath {string}")
    public void i_evaluate_the_xpath(String xpath) {
        try {
            result = context.getPointer(xpath);
        } catch (Exception e) {
            result = e;
        }
    }

    @Then("the result should be a pointer to the {string} Element")
    public void the_result_should_be_a_pointer_to_the_element(String elementName) {
         if (result instanceof Exception) {
             Assert.fail("Exception thrown: " + ((Exception) result).getMessage());
         }
         Assert.assertTrue("Result is not a Pointer", result instanceof Pointer);
         Pointer pointer = (Pointer) result;
         Object node = pointer.getNode();
         Assert.assertTrue("Node is not an Element", node instanceof Element);
         Element element = (Element) node;
         Assert.assertEquals("Element name mismatch", elementName, element.getNodeName());
    }
}
